const data = $input.first().json;
const q = data.question || '';
const mode = data.mode;
const sa = data.student_answer || '';
const ctx = data.rag_context || '';
let msg;
if (mode === 'explain') {
  msg = 'Topic: ' + q + '

Knowledge Base Context:
' + ctx + '

Respond ONLY with this exact JSON (no markdown):
{"explanation":"3-5 sentences","example":"one concrete example","quiz":[{"question":"q1","answer":"a1"},{"question":"q2","answer":"a2"},{"question":"q3","answer":"a3"}],"recommendation":"what to study next"}';
} else if (mode === 'quiz') {
  msg = 'Topic: ' + q + '

Knowledge Base Context:
' + ctx + '

Respond ONLY with this exact JSON (no markdown):
{"quiz":[{"question":"q1","answer":"a1"},{"question":"q2","answer":"a2"},{"question":"q3","answer":"a3"}]}';
} else {
  msg = 'Original question: ' + q + '
Student answer: ' + sa + '

Knowledge Base Context:
' + ctx + '

Respond ONLY with this exact JSON (no markdown):
{"correct":true,"partial_credit":false,"score":85,"feedback":"detailed feedback","correct_answer":"ideal answer"}';
}
return [{ json: { ...data, user_message: msg } }];

const orig = $node['Input'].json;
let llm_output;
try {
  const raw = ($input.first().json.output || '').trim();
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  llm_output = JSON.parse(cleaned);
} catch (e) {
  llm_output = { error: 'Failed to parse LLM response', raw: $input.first().json.output };
}
return [{ json: { ...orig, llm_output } }];
